import torch
import torch.nn as nn
import numpy as np
from torch.utils.data import TensorDataset, DataLoader


def load_npz(path='../data/rnn_data_next_instance/flight_data_for_rnn_next_instance.npz'):
    """loads npz file generated by data_prep.py for model training.

    Args:
        path (str): npz file generated by data_prep.py. Defaults to './flight_data_for_rnn.npz'.

    Returns:
        arrays of train, test and anchor variables.
    """
    data = np.load(path)
    
    X_train = data['X_train']
    y_train = data['y_train']
    anchor_train = data['anchor_train']
    X_test = data['X_test']
    y_test = data['y_test']
    anchor_test = data['anchor_test']
    
    return X_train, y_train, anchor_train, X_test, y_test, anchor_test


def dataloader(batch_size=64, task='next_instance'):
    """utilizes dataloader in pytorch.

    Returns:
        train_ds, test_ds, train_loader and test_loader.
    """
    
    if task == 'next_instance':
        X_train, y_train, anchor_train, X_test, y_test, anchor_test = load_npz(path='../data/rnn_data_next_instance/flight_data_for_rnn_next_instance.npz')
    elif task == 'next_ten_mins':
        X_train, y_train, anchor_train, X_test, y_test, anchor_test = load_npz(path='../data/rnn_data_next_ten_mins/flight_data_for_rnn_next_ten_mins.npz')
    
    X_train = torch.tensor(X_train, dtype=torch.float32)
    y_train = torch.tensor(y_train, dtype=torch.float32)
    anchor_train = torch.tensor(anchor_train, dtype=torch.float32)
    X_test = torch.tensor(X_test, dtype=torch.float32)
    y_test = torch.tensor(y_test, dtype=torch.float32)
    anchor_test = torch.tensor(anchor_test, dtype=torch.float32)
    
    train_ds = TensorDataset(X_train, y_train, anchor_train)
    test_ds = TensorDataset(X_test, y_test, anchor_test)
    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True)
    test_loader = DataLoader(test_ds, batch_size=batch_size, shuffle=False)
    
    return train_ds, test_ds, train_loader, test_loader

if __name__ == "__main__":
    dataloader()